import React, { useState, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { 
  TrendingUp, 
  TrendingDown, 
  Users, 
  ShoppingCart, 
  DollarSign, 
  Calendar, 
  BarChart3, 
  PieChart,
  FileText,
  Download,
  Upload,
  Filter,
  Search,
  Plus,
  Edit,
  Trash2,
  Eye,
  RefreshCw
} from 'lucide-react';
import Card from '../components/Card';
import DataTable from '../components/DataTable';
import FileImport from '../components/FileImport';
import MonthFilter from '../components/MonthFilter';
import { reportsApi } from '../api/reports';
import { exportApi } from '../api/export';
import { useClient } from '../contexts/ClientContext';

interface BusinessMetrics {
  totalRevenue: number;
  totalOrders: number;
  avgOrderValue: number;
  customerCount: number;
  conversionRate: number;
  growthRate: number;
}

interface RevenueData {
  month: string;
  revenue: number;
  orders: number;
  customers: number;
}

const BusinessDataNew: React.FC = () => {
  const { selectedClient } = useAuth();
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'overview' | 'data' | 'analytics'>('overview');
  const [searchTerm, setSearchTerm] = useState('');

  // Fetch reports data
  const { 
    data: reports = [], 
    isLoading: reportsLoading, 
    refetch: refetchReports 
  } = useQuery({
    queryKey: ['business-reports', selectedClient?.id, selectedMonth],
    queryFn: () => {
      if (!selectedClient) return Promise.resolve([]);
      return reportsApi.getReports({
        clientId: selectedClient.id,
        ...(selectedMonth ? { month: selectedMonth } : {})
      });
    },
    enabled: !!selectedClient,
  });

  // Calculate business metrics
  const businessMetrics: BusinessMetrics = React.useMemo(() => {
    if (!reports.length) {
      return {
        totalRevenue: 0,
        totalOrders: 0,
        avgOrderValue: 0,
        customerCount: 0,
        conversionRate: 0,
        growthRate: 0
      };
    }

    const totalRevenue = reports.reduce((sum, report) => sum + (report.revenue || 0), 0);
    const totalOrders = reports.reduce((sum, report) => sum + (report.orders || 0), 0);
    const customerCount = reports.reduce((sum, report) => sum + (report.customers || 0), 0);
    const totalClicks = reports.reduce((sum, report) => sum + (report.clicks || 0), 0);

    return {
      totalRevenue,
      totalOrders,
      avgOrderValue: totalOrders > 0 ? totalRevenue / totalOrders : 0,
      customerCount,
      conversionRate: totalClicks > 0 ? (totalOrders / totalClicks) * 100 : 0,
      growthRate: 12.5 // This would be calculated from historical data
    };
  }, [reports]);

  // Generate revenue trend data
  const revenueData: RevenueData[] = React.useMemo(() => {
    const monthlyData = new Map<string, { revenue: number; orders: number; customers: number }>();
    
    reports.forEach(report => {
      if (!report.date) return;
      
      const date = new Date(report.date);
      const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      
      if (!monthlyData.has(monthKey)) {
        monthlyData.set(monthKey, { revenue: 0, orders: 0, customers: 0 });
      }
      
      const existing = monthlyData.get(monthKey)!;
      existing.revenue += report.revenue || 0;
      existing.orders += report.orders || 0;
      existing.customers += report.customers || 0;
    });

    return Array.from(monthlyData.entries())
      .map(([month, data]) => ({
        month,
        ...data
      }))
      .sort((a, b) => a.month.localeCompare(b.month));
  }, [reports]);

  // Available months from data
  const availableMonths = React.useMemo(() => {
    const months = new Set<string>();
    reports.forEach(report => {
      if (report.date) {
        const date = new Date(report.date);
        const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
        months.add(monthKey);
      }
    });
    return Array.from(months).sort().reverse();
  }, [reports]);

  // Filter reports based on search term
  const filteredReports = React.useMemo(() => {
    if (!searchTerm) return reports;
    return reports.filter(report => 
      Object.values(report).some(value => 
        String(value).toLowerCase().includes(searchTerm.toLowerCase())
      )
    );
  }, [reports, searchTerm]);

  const handleClearAllData = async () => {
    if (window.confirm('Are you sure you want to clear all business data? This action cannot be undone.')) {
      try {
        // In a real app, this would call a delete API
        console.log('Clearing all business data for client:', selectedClient?.id);
        await refetchReports();
      } catch (error) {
        console.error('Error clearing data:', error);
      }
    }
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(value);
  };

  const formatPercentage = (value: number) => {
    return `${value.toFixed(1)}%`;
  };

  if (!selectedClient) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <Card>
          <div className="text-center py-12">
            <div className="w-16 h-16 mx-auto mb-4 bg-blue-100 rounded-full flex items-center justify-center">
              <BarChart3 className="w-8 h-8 text-blue-600" />
            </div>
            <h2 className="text-xl font-semibold text-gray-900 mb-2">
              Select a Client
            </h2>
            <p className="text-gray-600">
              Please select a client to view business data and analytics.
            </p>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900 mb-2">Business Data</h1>
        <p className="text-gray-600">
          Comprehensive business analytics and data management for {selectedClient.name}
        </p>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-gray-200 mb-8">
        <nav className="-mb-px flex space-x-8">
          {[
            { id: 'overview', label: 'Overview', icon: BarChart3 },
            { id: 'data', label: 'Data Management', icon: FileText },
            { id: 'analytics', label: 'Analytics', icon: PieChart }
          ].map(tab => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === tab.id
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                <Icon className="w-4 h-4 mr-2" />
                {tab.label}
              </button>
            );
          })}
        </nav>
      </div>

      {/* Overview Tab */}
      {activeTab === 'overview' && (
        <div className="space-y-8">
          {/* Key Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <Card>
              <div className="flex items-center">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 bg-green-100 rounded-lg flex items-center justify-center">
                    <DollarSign className="w-5 h-5 text-green-600" />
                  </div>
                </div>
                <div className="ml-4">
                  <div className="text-sm font-medium text-gray-500">Total Revenue</div>
                  <div className="text-2xl font-bold text-gray-900">
                    {formatCurrency(businessMetrics.totalRevenue)}
                  </div>
                  <div className="flex items-center text-sm">
                    <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                    <span className="text-green-600">{formatPercentage(businessMetrics.growthRate)}</span>
                  </div>
                </div>
              </div>
            </Card>

            <Card>
              <div className="flex items-center">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center">
                    <ShoppingCart className="w-5 h-5 text-blue-600" />
                  </div>
                </div>
                <div className="ml-4">
                  <div className="text-sm font-medium text-gray-500">Total Orders</div>
                  <div className="text-2xl font-bold text-gray-900">
                    {businessMetrics.totalOrders.toLocaleString()}
                  </div>
                  <div className="flex items-center text-sm">
                    <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                    <span className="text-green-600">+8.2%</span>
                  </div>
                </div>
              </div>
            </Card>

            <Card>
              <div className="flex items-center">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 bg-purple-100 rounded-lg flex items-center justify-center">
                    <Users className="w-5 h-5 text-purple-600" />
                  </div>
                </div>
                <div className="ml-4">
                  <div className="text-sm font-medium text-gray-500">Customers</div>
                  <div className="text-2xl font-bold text-gray-900">
                    {businessMetrics.customerCount.toLocaleString()}
                  </div>
                  <div className="flex items-center text-sm">
                    <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                    <span className="text-green-600">+15.3%</span>
                  </div>
                </div>
              </div>
            </Card>

            <Card>
              <div className="flex items-center">
                <div className="flex-shrink-0">
                  <div className="w-8 h-8 bg-orange-100 rounded-lg flex items-center justify-center">
                    <BarChart3 className="w-5 h-5 text-orange-600" />
                  </div>
                </div>
                <div className="ml-4">
                  <div className="text-sm font-medium text-gray-500">Avg Order Value</div>
                  <div className="text-2xl font-bold text-gray-900">
                    {formatCurrency(businessMetrics.avgOrderValue)}
                  </div>
                  <div className="flex items-center text-sm">
                    <TrendingDown className="w-4 h-4 text-red-500 mr-1" />
                    <span className="text-red-600">-2.1%</span>
                  </div>
                </div>
              </div>
            </Card>
          </div>

          {/* Revenue Trend Chart */}
          <Card>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-900">Revenue Trend</h3>
              <div className="flex items-center space-x-2">
                <Calendar className="w-4 h-4 text-gray-400" />
                <span className="text-sm text-gray-600">Last 6 months</span>
              </div>
            </div>
            <div className="h-64 flex items-end space-x-2">
              {revenueData.slice(-6).map((data, index) => {
                const maxRevenue = Math.max(...revenueData.map(d => d.revenue));
                const height = maxRevenue > 0 ? (data.revenue / maxRevenue) * 200 : 0;
                
                return (
                  <div key={data.month} className="flex-1 flex flex-col items-center">
                    <div className="text-xs text-gray-500 mb-2">
                      {formatCurrency(data.revenue)}
                    </div>
                    <div 
                      className="w-full bg-blue-500 rounded-t-sm transition-all duration-500"
                      style={{ height: `${height}px` }}
                    />
                    <div className="text-xs text-gray-600 mt-2">
                      {new Date(data.month + '-01').toLocaleDateString('en-US', { 
                        month: 'short',
                        year: '2-digit'
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
      )}

      {/* Data Management Tab */}
      {activeTab === 'data' && (
        <div className="space-y-6">
          {/* Controls */}
          <Card>
            <div className="flex flex-wrap items-center justify-between gap-4">
              <div className="flex items-center space-x-4">
                <div className="relative">
                  <Search className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                  <input
                    type="text"
                    placeholder="Search data..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <MonthFilter
                  value={selectedMonth}
                  onChange={setSelectedMonth}
                  months={availableMonths}
                  loading={reportsLoading}
                />
              </div>
              
              <div className="flex items-center space-x-2">
                <FileImport />
                <a
                  href={`${exportApi.exportCsv()}?clientId=${selectedClient.id}`}
                  className="btn-secondary inline-flex items-center"
                >
                  <Download className="w-4 h-4 mr-2" />
                  Export
                </a>
                <button
                  onClick={handleClearAllData}
                  className="btn-danger inline-flex items-center"
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  Clear All
                </button>
                <button
                  onClick={() => refetchReports()}
                  className="btn-secondary inline-flex items-center"
                >
                  <RefreshCw className="w-4 h-4 mr-2" />
                  Refresh
                </button>
              </div>
            </div>
          </Card>

          {/* Data Summary */}
          <Card>
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-lg font-semibold text-gray-900">Data Summary</h3>
                <p className="text-sm text-gray-600 mt-1">
                  {filteredReports.length} record{filteredReports.length !== 1 ? 's' : ''} found
                  {selectedMonth && ` for ${selectedMonth}`}
                </p>
              </div>
              <div className="text-right">
                <div className="text-sm text-gray-500">Total Revenue</div>
                <div className="text-xl font-bold text-green-600">
                  {formatCurrency(businessMetrics.totalRevenue)}
                </div>
              </div>
            </div>
          </Card>

          {/* Data Table */}
          <DataTable
            data={filteredReports}
            loading={reportsLoading}
            onView={(report) => {
              alert(JSON.stringify(report, null, 2));
            }}
            onEdit={(report) => {
              console.log('Edit report:', report);
            }}
          />
        </div>
      )}

      {/* Analytics Tab */}
      {activeTab === 'analytics' && (
        <div className="space-y-8">
          {/* Performance Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Conversion Funnel</h3>
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Website Visitors</span>
                  <span className="text-sm font-medium">10,000</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div className="bg-blue-600 h-2 rounded-full" style={{ width: '100%' }}></div>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Product Views</span>
                  <span className="text-sm font-medium">3,500</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div className="bg-blue-600 h-2 rounded-full" style={{ width: '35%' }}></div>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Add to Cart</span>
                  <span className="text-sm font-medium">1,200</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div className="bg-blue-600 h-2 rounded-full" style={{ width: '12%' }}></div>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Purchases</span>
                  <span className="text-sm font-medium">{businessMetrics.totalOrders}</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div className="bg-green-600 h-2 rounded-full" style={{ width: '8%' }}></div>
                </div>
              </div>
            </Card>

            <Card>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Key Performance Indicators</h3>
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Conversion Rate</span>
                  <span className="text-sm font-bold text-green-600">
                    {formatPercentage(businessMetrics.conversionRate)}
                  </span>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Customer Lifetime Value</span>
                  <span className="text-sm font-bold text-blue-600">
                    {formatCurrency(businessMetrics.avgOrderValue * 3.2)}
                  </span>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Return Customer Rate</span>
                  <span className="text-sm font-bold text-purple-600">42.3%</span>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Cart Abandonment Rate</span>
                  <span className="text-sm font-bold text-red-600">65.7%</span>
                </div>
              </div>
            </Card>
          </div>

          {/* Revenue Breakdown */}
          <Card>
            <h3 className="text-lg font-semibold text-gray-900 mb-6">Revenue Breakdown by Month</h3>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Month
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Revenue
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Orders
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Customers
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Avg Order Value
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {revenueData.map((data) => (
                    <tr key={data.month} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                        {new Date(data.month + '-01').toLocaleDateString('en-US', { 
                          month: 'long',
                          year: 'numeric'
                        })}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {formatCurrency(data.revenue)}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {data.orders.toLocaleString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {data.customers.toLocaleString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {data.orders > 0 ? formatCurrency(data.revenue / data.orders) : '$0'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

export default BusinessDataNew;
